      <div class="section-title">積分配置</div>
    </div>
    <el-form ref="form" :model="form" label-position="left" label-width="180px">
      <div class="section-body">
        <el-form-item label="積分：">
          <el-switch
            v-model="form.isOpenMemberPoint"
            :width="60"
            active-value="true"
            inactive-value="false"
            inactive-color="#ccc"
            active-text="開啟"
            inactive-text="關閉"
            active-color="#13ce66"
            @change="isOpenMemberPointHandle"
          />
        </el-form-item>
        <el-form-item label="顯示名稱：">
          <el-input v-model="form.name" placeholder="" style="width: 120px" :max="8" />
          <el-tooltip
            class="item"
            effect="dark"
            content="設置店鋪內積分對應的顯示名稱"
            placement="top"
          >
            <i class="el-icon-question" />
          </el-tooltip>
        </el-form-item>
        <div v-if="form.isOpenMemberPoint == 'true'">
          <el-form-item label="獲取方式：">
            <el-radio-group v-model="form.access" @change="changeAccess">
              <el-radio label="order"> 訂單 </el-radio>
              <el-radio label="items"> 商品 </el-radio>
            </el-radio-group>
            <p v-if="access == 'order'" class="frm-tips">說明：可按訂單金額比例獲取</p>
            <p v-if="access == 'items'" class="frm-tips">說明：可按單商品設置的積分值獲取</p>
          </el-form-item>
          <el-form-item v-if="access == 'order'" label="獲取比例：">
            訂單金額1元台幣 獲得<el-input
              v-model="form.gain_point"
              type="number"
              placeholder=""
              style="width: 120px"
              :min="1"
              :max="9999999"
            />積分
          </el-form-item>

          <el-form-item v-if="access == 'order'" label="運費配置：">
            <el-radio-group v-model="form.include_freight">
              <el-radio label="true"> 包含 </el-radio>
              <el-radio label="false"> 不包含 </el-radio>
            </el-radio-group>
            <p v-if="include_freight == 'true'" class="frm-tips">
              說明：可設置訂單中運費部分金額是否可獲取積分
            </p>
            <p v-if="include_freight == 'false'" class="frm-tips">
              說明：可設置訂單中運費部分金額是否可獲取積分
            </p>
          </el-form-item>
          <el-form-item label="積分獲取限制：">
            每月最多獲取<el-input
              v-model="form.gain_limit"
              type="number"
              placeholder=""
              style="width: 120px"
              :min="1"
              :max="9999999"
            />積分
            <div class="frm-tips">不限制請填寫999999</div>
          </el-form-item>
          <el-form-item label="獲取時間：">
            訂單完成<el-input
              v-model="form.gain_time"
              type="number"
              placeholder=""
              style="width: 120px"
              :min="1"
              :max="9999999"
            />天，獲取積分
          </el-form-item>
          <template v-if="!VERSION_IN_PURCHASE">
            <el-form-item label="積分抵扣：">
              <el-switch
                v-model="form.isOpenDeductPoint"
                :width="60"
                active-value="true"
                inactive-value="false"
                inactive-color="#ccc"
                active-text="開啟"
                inactive-text="關閉"
                active-color="#13ce66"
                @change="isOpenMemberPointHandle"
              />
            </el-form-item>
            <el-form-item label="每單抵扣上限：">
              <el-input
                v-model="form.deduct_proportion_limit"
                type="number"
                placeholder=""
                style="width: 120px"
                :min="1"
                :max="100"
              />% 上限範圍：1<=x<=100
            </el-form-item>
            <el-form-item label="抵扣比例：">
              <el-input
                v-model="form.deduct_point"
                type="number"
                placeholder=""
                style="width: 120px"
                :min="1"
                :max="9999999"
              />
              積分 抵扣1元台幣
            </el-form-item>
            <el-form-item label="多倍積分活動：">
              <el-switch
                v-model="form.mi_is_open"
                :width="60"
                active-value="1"
                inactive-value="2"
                inactive-color="#ccc"
                active-text="開啟"
                inactive-text="關閉"
                active-color="#13ce66"
              />
            </el-form-item>
            <el-form-item label="有效期：">
              <el-date-picker
                v-model="activity_date"
                type="datetimerange"
                range-separator="至"
                start-placeholder="生效時間"
                end-placeholder="過期時間"
                value-format="yyyy-MM-dd HH:mm:ss"
                :default-time="['00:00:00', '23:59:59']"
              />
            </el-form-item>
            <el-form-item label="倍數：">
              <el-input
                v-model="form.mi_multiple"
                type="number"
                placeholder=""
                style="width: 120px"
                :min="1"
                :max="9999999"
              />
              倍
            </el-form-item>
            <el-form-item label="多倍積分活動文案：">
              <el-input v-model="form.mi_record_activities" placeholder="" style="width: 400px"/>
            </el-form-item>
            <el-form-item label="積分快到期是否開啟提醒：">
              <el-switch
                v-model="form.mi_expiration_reminder"
                :width="60"
                active-value="1"
                inactive-value="2"
                inactive-color="#ccc"
                active-text="開啟"
                inactive-text="關閉"
                active-color="#13ce66"
              />
            </el-form-item>
            <el-form-item label="提醒文案：">
              <el-input v-model="form.mi_reminder_copy" placeholder="" style="width: 400px"/>
            </el-form-item>
            <el-form-item label="清零時間：">
              獲得多倍積分
              <el-input
                v-model="form.mi_zeroing_time"
                type="number"
                placeholder=""
                style="width: 120px"
                :min="1"
                :max="9999999"
              />
              天內清零
            </el-form-item>
            <el-form-item label="積分規則：">
              <SpRichText v-model="form.rule_desc" />
            </el-form-item>
          </template>
          <!-- <el-form-item label="購物贈送積分">
                       消費滿<el-input  type="number"  v-model="form.deduct_shopping" placeholder="" style="width: 120px;" :min="1" :max="9999999"/>元 贈送1積分
                   </el-form-item> -->
        </div>
      </div>
      <div class="section-footer with-border content-center">
        <el-button type="primary" @click="save"> 保 存 </el-button>
      </div>
    </el-form>
  </div>
</template>
<script>
import { savePointRule, getPointRule } from '../../../api/promotions'

export default {
  data() {
    return {
      form: {
        isOpenMemberPoint: 'false',
        gain_point: 1,
        gain_limit: 999999,
        gain_time: 3,
        isOpenDeductPoint: false,
        deduct_point: 0,
        deduct_proportion_limit: 1,
        access: 'order',
        include_freight: 'true',
        mi_is_open: '2',
        mi_start_date: '',
        mi_end_date: '',
        mi_multiple: 1,
        mi_record_activities: '',
        mi_expiration_reminder: '2',
        mi_reminder_copy: '',
        mi_zeroing_time: 0,
        rule_desc: ''
      },
      activity_date: [],
      access: 'order',
      include_freight: 'true'
    }
  },
  mounted() {
    this.getPointRule()
  },
  methods: {
    isOpenMemberPointHandle(val) {
      if (val == 'false') {
        this.$confirm(
          '若關閉該設置，營銷 - 分銷推廣 - 傭金獎勵, 自動變更為現金獎勵方式。',
          '提示',
          {
            confirmButtonText: '確定',
            cancelButtonText: '取消',
            type: 'warning'
          }
        )
          .then(() => {})
          .catch(() => {
            this.form.isOpenMemberPoint = 'true'

            this.$message({
              type: 'info',
              message: '已取消'
            })
          })
      }
      console.log(val)
    },
    getPointRule() {
      getPointRule().then((response) => {
        this.form = response.data.data
        ;(this.access = this.form.access), (this.include_freight = this.form.include_freight)
        this.activity_date = [this.form.mi_start_date, this.form.mi_end_date]
      })
    },
    save() {
      if (this.form.isOpenMemberPoint) {
        if (this.form.gain_point <= 0 || this.form.gain_time <= 0) {
          this.$message({ message: '請配置獲取積分參數', type: 'error' })
          return
        }
        if (this.form.gain_limit == '' || this.form.gain_limit == 0) {
          this.form.gain_limit = 9999999
        }
        if (this.form.gain_limit < this.form.gain_point) {
          this.$message({ message: '獲取積分限制不能小於獲取積分比例', type: 'error' })
          return
        }

        if (this.form.isOpenDeductPoint) {
          if (this.form.deduct_point == '') {
            this.$message({ message: '請配置積分抵扣參數', type: 'error' })
            return
          }
          if (this.form.deduct_proportion_limit == '' || this.form.deduct_proportion_limit == 0) {
            this.form.deduct_proportion_limit = 1
          }
        }
      }
      if (this.activity_date.length > 0) {
        this.form.mi_start_date = this.activity_date[0]
        this.form.mi_end_date = this.activity_date[1]
      } else {
        this.form.mi_start_date = '';
        this.form.mi_end_date = '';
      }
      savePointRule(this.form).then((response) => {
        this.getPointRule()
        this.$message({
          message: '儲存成功',
          type: 'success'
        })
      })
    },
    changeAccess(type) {
      this.access = type
      if (this.access == 'items') {
      }
    }
  }
}
</script>

<style lang="scss" scoped>
.point-rule {
  height: auto !important;
}
</style>
